css:
.loader {
  color: var(--loader-color, #9333ea);
  height: 54px;
  aspect-ratio: 1;
  border: 3px solid var(--loader-secondary-color, #f0abfc);
  border-top: none;
  position: relative;
}
.loader:before {
  content: "";
  position: absolute;
  width: 30%;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #9333ea);
  animation: 
    l5-0 .5s cubic-bezier(0,800,1,800) infinite -.25s,
    l5-1 .5s linear infinite alternate;
}
@keyframes l5-0 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}
@keyframes l5-1 {
  0%,8%  {left: 0%}
  92%,to {left: 70%}
}
